        findings.push(
          finding({
            id: check.id,
            title: check.title,
            severity: "medium",
            category: "documentation",
            description:
              "The README is missing a section agents commonly need to orient themselves.",
            evidence: [`README.md does not contain any of: ${check.terms.join(", ")}.`],
