  "freshness_and_consistency"
] as const;
export const scanProfiles = [
  "default",
  "devtool",
  "api",
  "mcp",
  "docs",
  "library",
  "internal"
] as const;
export const scoreConfidenceLevels = ["high", "medium", "low"] as const;
export const suggestedFixTypes = [
  "create_file",
